export default function register(bot) {
  bot.command("help", async (ctx) => {
    const text = [
      "How to use:",
      "1) Paste a TikTok URL in this chat.",
      "2) Wait a moment while I fetch and upload the video.",
      "",
      "Supported URL formats:",
      "- https://www.tiktok.com/...",
      "- https://tiktok.com/...",
      "- https://vm.tiktok.com/...",
      "- https://vt.tiktok.com/...",
      "",
      "Common issues:",
      "- Private video: the downloader can’t access it.",
      "- Region locked: the API might not be able to fetch it.",
      "- API down or rate limited: try again in a few minutes.",
      "",
      "Fallback behavior:",
      "I try sending as a Telegram video first. If that fails, I send it as a document. If that still fails, I’ll send you a direct download link.",
    ].join("\n");

    await ctx.reply(text);
  });
}

loader.js.content:
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath, pathToFileURL } from "node:url";

export async function registerCommands(bot) {
  const dir = path.dirname(fileURLToPath(import.meta.url));

  const commandFiles = fs
    .readdirSync(dir)
    .filter(
      (file) =>
        file.endsWith(".js") &&
        file !== "loader.js" &&
        !file.startsWith("_")
    );

  for (const file of commandFiles) {
    const url = pathToFileURL(path.join(dir, file)).toString();
    const mod = await import(url);
    const handler = mod?.default || mod?.register;

    if (typeof handler === "function") {
      await handler(bot);
    } else {
      console.warn("[commands] " + file + " has no default/register export; skipped.");
    }
  }
}

